+// deno-lint-ignore-file no-explicit-any
+import { ConfigParseError } from "./errors.ts";
+import type { ConfigOptions } from "./types.ts";
+
+export interface LoadedConfig {
+  path?: string;
+  values: Record<string, unknown>;
+}
+
+const DEFAULT_FORMATS = [".json", ".rc"];
+
+export async function loadConfig(options: ConfigOptions): Promise<LoadedConfig> {
+  const values: Record<string, unknown> = {};
+  let path: string | undefined;
+
+  for (const searchPath of options.searchPaths ?? ["."]) {
+    for (const format of options.formats ?? DEFAULT_FORMATS) {
+      const filename = format === ".rc"
+        ? `.${options.name}rc`
+        : `${options.name}${format}`;
+      const config = await readConfigFile(searchPath, filename);
+      if (!config) continue;
+
+      const parsed = parseConfig(config.path, config.content, format, options.parser);
+      const flattened = flattenConfig(parsed);
+      // Earlier paths win when configs are merged.
+      Object.assign(values, flattened, values);
+      path ??= config.path;
+      if (!options.mergeConfigs) return { path, values };
+      break;
+    }
+  }
+
+  return { path, values };
+}
+
+function parseConfig(
+  path: string,
+  content: string,
+  format: string,
+  parser?: ConfigOptions["parser"],
+): Record<string, unknown> {
+  try {
+    const parsed = parser
+      ? parser(content)
+      : format === ".rc"
+      ? parseRc(content)
+      : JSON.parse(content);
+    if (!isPlainObject(parsed)) throw new Error("Config must contain a plain object.");
+    return parsed;
+  } catch (error) {
+    throw new ConfigParseError(path, error);
+  }
+}
+
+function parseRc(content: string): Record<string, unknown> {
+  const values: Record<string, unknown> = {};
+  for (const rawLine of content.split(/\\r?\
/)) {
+    const line = rawLine.trim();
+    if (!line || line.startsWith("#")) continue;
+    const match = /^([^=]+?)\\s*=\\s*(.*)$/.exec(line);
+    if (!match) throw new Error(`Invalid RC line: ${rawLine}`);
+    const key = match[1].trim();
+    let value = match[2].trim();
+    if (!key) throw new Error(`Invalid RC line: ${rawLine}`);
+    if (value.startsWith('"')) {
+      if (!value.endsWith('"') || value.length < 2) {
+        throw new Error(`Unterminated quoted value: ${rawLine}`);
+      }
+      value = value.slice(1, -1);
+    }
+    values[key] = coerceRcValue(value);
+  }
+  return values;
+}
+
+function coerceRcValue(value: string): string | number | boolean {
+  if (value === "true") return true;
+  if (value === "false") return false;
+  return /^[-+]?(?:\\d+\\.?\\d*|\\.\\d+)(?:[eE][-+]?\\d+)?$/.test(value)
+    ? Number(value)
+    : value;
+}
+
+function flattenConfig(
+  value: Record<string, unknown>,
+  prefix = "",
+): Record<string, unknown> {
+  const result: Record<string, unknown> = {};
+  for (const [key, child] of Object.entries(value)) {
+    const name = toCamelCase(key);
+    const path = prefix ? `${prefix}.${name}` : name;
+    if (isPlainObject(child)) Object.assign(result, flattenConfig(child, path));
+    else result[path] = child;
+  }
+  return result;
+}
+
+export function toCamelCase(value: string): string {
+  return value.replace(/-([a-zA-Z0-9])/g, (_, char: string) => char.toUpperCase());
+}
+
+function isPlainObject(value: unknown): value is Record<string, unknown> {
+  if (!value || typeof value !== "object" || Array.isArray(value)) return false;
+  const prototype = Object.getPrototypeOf(value);
+  return prototype === Object.prototype || prototype === null;
+}
+
+async function readConfigFile(
+  searchPath: string,
+  filename: string,
+): Promise<{ path: string; content: string } | undefined> {
+  const { Deno, process } = globalThis as any;
+  if (Deno) {
+    const candidate = `${searchPath.replace(/[\\\\/]$/, "")}/${filename}`;
+    try {
+      const path = await Deno.realPath(candidate);
+      return { path, content: await Deno.readTextFile(path) };
+    } catch (error) {
+      if (error instanceof Deno.errors.NotFound) return undefined;
+      throw error;
+    }
+  }
+
+  const path = await import("node:path");
+  const fs = await import("node:fs/promises");
+  const candidate = path.resolve(process?.cwd?.() ?? ".", searchPath, filename);
+  try {
+    return { path: candidate, content: await fs.readFile(candidate, "utf8") };
+  } catch (error: any) {
+    if (error?.code === "ENOENT") return undefined;
+    throw error;
+  }
+}
