+      const parsed = parseConfig(config.path, config.content, format, options.parser);
+      const flattened = flattenConfig(parsed);
+      // Earlier paths win when configs are merged.
+      Object.assign(values, flattened, values);
+      path ??= config.path;
+      if (!options.mergeConfigs) return { path, values };
+      break;
+    }
+  }
+
+  return { path, values };
+}
+
+function parseConfig(
+  path: string,
+  content: string,
+  format: string,
+  parser?: ConfigOptions["parser"],
+): Record<string, unknown> {
+  try {
+    const parsed = parser
+      ? parser(content)
+      : format === ".rc"
+      ? parseRc(content)
+      : JSON.parse(content);
+    if (!isPlainObject(parsed)) throw new Error("Config must contain a plain object.");
+    return parsed;
+  } catch (error) {
